var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"여러분! 오래 기다리셨죠?!","JPN":"みなさま！　お待たせしました！！","ENG":"Everyone, thank you for your patience.","TWN":"讓大家久等了！"},"stage":{"bg":"SS_SPORTS_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"지금부터 스타디움의 전광판에 주목해 주세요!","JPN":"これよりスタジアムの電光掲示板に注目してください！","ENG":"Please watch the big screen in the stadium!","TWN":"現在開始請注意看體育場的大螢幕！"},"stage":{"bg":"SS_SPORTS_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"곧 마지막 경기가 시작되니까요!","JPN":"まもなく最後の試合が始まります！","ENG":"The final game will begin shortly!","TWN":"最後一場比賽即將開始！"},"stage":{"bg":"SS_SPORTS_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시가 화난 건 내 잘못이야.","JPN":"ケイシーが怒ったのは私のせいだ。","ENG":"It's my fault that Kaci got upset.","TWN":"惹卡西生氣是我的錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 친구를 화나게 했어.","JPN":"私が友達を怒らせてしまった。","ENG":"I made my friend angry.","TWN":"我惹朋友生氣了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......꼭 사과해야 해!","JPN":"……絶対に謝らないと！","ENG":"I have to apologize!","TWN":"……我一定要道歉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Pant* *Pant*","TWN":"哈啊……哈啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"다행이다...... 여기 있었구나.","JPN":"よかった……ここにいたんだね。","ENG":"Thank goodness... You're here.","TWN":"太好了……原來你在這兒啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"저기, 케이시......","JPN":"あの、ケイシー……","ENG":"Look, Kaci...","TWN":"那個，卡西……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"미안해! 우리 같이 이기기로 약속했는데!","JPN":"ごめんね！　私たちはみんなで勝つと約束したのに！","ENG":"I'm sorry! We promised to win together!","TWN":"對不起！我們約好了一起贏比賽的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 바보처럼 약속을 어겨 버렸어!","JPN":"私が約束を破っちゃったの！　悪いのは私だよ！","ENG":"But I broke the promise like a fool!","TWN":"可我卻像個傻瓜一樣失約了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까...... 나, 사과하고 싶어!","JPN":"だから……謝りたいの！","ENG":"So... I want to apologize!","TWN":"所以……我，想跟你道歉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이거, 받아 줄래?","JPN":"これ、受け取ってくれる？","ENG":"Here, will you take this?","TWN":"這個，你願意收下嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아르티한테 네가 꽃을 좋아한다고 들어서 꽃다발을 만들었어.","JPN":"アルティからケイシーは花が好きと聞いて花束を作ったの。","ENG":"Arti told me you like flowers, so I made you a bouquet.","TWN":"我聽阿爾蒂說你喜歡花，所以做了一個花束。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"블루로즈야. 이 섬에서만 피는 꽃이래.","JPN":"ブルーローズだよ。この島でしか咲かない花なんだって。","ENG":"They're blue roses. They grow only on this island.","TWN":"是藍玫瑰，聽說只有這個島上才有。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"분명 너한테 잘 어울릴 거야.","JPN":"きっとケイシーに似合うと思う。","ENG":"I'm sure they will go well with you.","TWN":"一定很適合你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까, 케이시......","JPN":"だから、ケイシー……","ENG":"So, Kaci...","TWN":"所以，卡西……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시......?","JPN":"ケイシー……？","ENG":"Kaci?","TWN":"卡西……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시, 내 말 안 들려?","JPN":"ケイシー、私の声が聞こえないの？","ENG":"Kaci, didn't you hear me?","TWN":"卡西，你聽不見我說話嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Hmm?","TWN":"哎呀？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"미안해...... 잘 못 들었어.","JPN":"ごめん……聞こえなかったの。","ENG":"I’m sorry. I didn't hear you well.","TWN":"對不起……我沒聽清楚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 괜찮아. 내가 말을 너무 작게 했나 봐.","JPN":"あ、大丈夫だよ。私の声が小さすぎたみたい。","ENG":"Oh, it's okay. Maybe my voice was too low.","TWN":"啊，沒關係，可能是我說話聲音太小了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런데 너...... 누구야?","JPN":"ところで、君は……誰？","ENG":"Erm, but... Do I know you?","TWN":"不過……你是誰呀？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"어......?","JPN":"え……？","ENG":"Err?","TWN":"啊……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"미안. 나, 네가 누군지 모르겠어.","JPN":"ごめん。あたし、君のことを知らないの。","ENG":"Sorry. But I don't remember you.","TWN":"對不起，我，不認識你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"선생님한테 기억력이 좋다고 칭찬 많이 받았는데...... 혹시 다른 반 친구야?","JPN":"先生には記憶力がいいって褒められるほうなんだけど……もしかして他のクラスの子？","ENG":"Ugh, the teacher said I have a good memory... Do we study in the same homeroom?","TWN":"老師經常誇我記憶力好……莫非你是別的班的同學？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 아르티. 케이시가...... 날 기억 못 해.","JPN":"ア、アルティ。ケイシーが……私のことを覚えていないの。","ENG":"A-Arti. Kaci... doesn't remember me.","TWN":"阿，阿爾蒂，卡西……不記得我了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시! 여기서 혼자 뭐하고 있는 거야?","JPN":"ケイシー！　ここで一人で何してるんだ？","ENG":"Kaci! What are you doing here alone?","TWN":"卡西！你一個人在這兒幹什麼呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까...... 화관을 만들고 있었는데......","JPN":"えっと……花冠を作っていたけど……","ENG":"Uh... I was making a garland...","TWN":"那個……我在編花冠……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"누구한테 주려고 했는지 기억이 안 나. 선생님일까......?","JPN":"誰にあげようとしたのか思い出せないの。先生かな……？","ENG":"But I don't remember whose it was. Was it for the teacher?","TWN":"可我不記得想送給誰了，是老師嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"으음? 선생님 생일 선물은 벌써 드리지 않았어?","JPN":"うん？　先生の誕生日プレゼントはもう渡したんじゃない？","ENG":"Huh? Didn't you already give her a birthday present?","TWN":"呃嗯？老師的生日禮物不是已經送過了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아......","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"또...... 이렇게 되는구나......","JPN":"また……こうなってしまう……","ENG":"So it happens... again...","TWN":"又……變成這個樣子了……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"바보같이 기대하고 있었어......","JPN":"バカみたいに期待しちゃった……","ENG":"Silly me... for hoping otherwise...","TWN":"我卻像個傻瓜似的滿懷期待……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......얘들아. 나, 너희들한테 두 번씩이나 거짓말했어.","JPN":"……あのね。実は私、二人に二度も嘘をついたの。","ENG":"Kaci, Arti. I lied to you twice.","TWN":"……夥伴們，我，我對你們說了兩次謊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"운동회에 나온 거...... 이번이 처음이 아니야.","JPN":"運動会に出たのは……今回が初めてじゃないの。","ENG":"It's not my first time... playing in the Field Day...","TWN":"我不是第一次……參加運動會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"사람들 눈에 띄고 싶어서...... 누구라도 날 봐 주면 좋을 것 같아서......","JPN":"人目につきたくて……誰でもいいから私を見てほしくて……","ENG":"I wanted to be noticed... I wanted anyone to be able to see me...","TWN":"我想讓人們看見我……不管是誰，只要能看到我就好……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"대회 때마다 혼자 나가서 뛰어다녔어.","JPN":"大会のたびに一人で出て、走り回っていたの。","ENG":"Every Field Day, I went out and ran around.","TWN":"所以每次開運動會時我都會自己加入。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그렇지만 아무도 날 알아봐 주지 않아.","JPN":"それでも誰も私に気づいてくれなかった。","ENG":"But no one ever looked at me...","TWN":"可是沒有一個人認出我。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"공 묘기도 연습하고, 그림 그리기도 연습하고, 운동도 열심히 했는데......","JPN":"ボールの技も、お絵描きも、運動だって一生懸命に頑張ったのに……","ENG":"I worked on ball tricks, practiced painting, and played really hard in sports games...","TWN":"我練了球技，練了畫畫，還很認真地運動……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"상장을 받아도, 꼴찌를 해도 아무도 몰라.","JPN":"賞状をもらっても、ビリになっても誰も気づかない。","ENG":"But even if I received an award, or came in the last place... no one knew about it.","TWN":"可是不管我拿到名次也好，還是排在最後，都沒有人知道。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"선생님이 칭찬해 주지도 않고, 놀리는 애들도 없어...... ","JPN":"先生に褒めてもらえることも、からかってくれる友達もいないの。","ENG":"Teachers didn't compliment me, and kids didn't make fun of me... ","TWN":"沒有老師誇獎我，也沒有同學嘲笑我……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 노력해도, 다른 사람들은 알아 주지 않아.","JPN":"私がいくら努力しても、他の人たちはわかってくれない。","ENG":"No matter how hard I try, people just don't notice me.","TWN":"不管我怎麼努力，別人都不知道。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까 운동회에 나가도 소용없다고 말하려고 했는데......","JPN":"だから運動会に出ても無駄だと言おうとしたのに……","ENG":"So I was going to tell you that it was useless to participate in Field Day...","TWN":"所以，我想說參加運動會也沒用……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러려고 했는데......","JPN":"そうしようと思ったのに……","ENG":"I really was...","TWN":"我本想那樣說的……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러지 못했어.","JPN":"できなかった。","ENG":"But I couldn't.","TWN":"可是最終沒能說出來。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시가 내 손을 잡아 주고, 아르티가 소원구슬에 대해 말해 줬을 때......","JPN":"ケイシーが私の手を握ってくれて、アルティが願い玉について話してくれた時……","ENG":"When Kaci held my hand, and Arti told me about the Wishing Ball...","TWN":"卡西抓住我的手，阿爾蒂跟我說許願珠的事時……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이번에는 다를지도 모른다고 생각했어.","JPN":"今回は違うかもしれないと思った。","ENG":"I thought maybe it would be different this time.","TWN":"我還在想這次說不定會不一樣，"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"날...... 끝까지 기억해 줄지도 모른다고 생각했어.","JPN":"私を……最後まで憶えていてくれるかもしれないと思ったの。","ENG":"Maybe... you would remember me, no matter what.","TWN":"說不定……真的會有人一直記得我。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그래서...... 기다릴 수 있다고 한 건데......","JPN":"それで、待てると言ったのに……","ENG":"That's why... I told you I could wait...","TWN":"所以……我才會說我可以等……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"미안해. 케이시, 아르티......","JPN":"ごめんね。ケイシー、アルティ……","ENG":"Sorry. Kaci, Arti...","TWN":"對不起，卡西，阿爾蒂……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"나...... 이젠 그냥 포기할래.","JPN":"私……もう諦めることにする。","ENG":"I'm... giving up now.","TWN":"我……想放棄了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......미안해.","JPN":"……ごめんね。","ENG":"I'm so sorry.","TWN":"……對不起。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};